UPDATE job
company_id = #{companyId}, title = #{title}, company_name = #{companyName}, source_site = #{sourceSite}, unique_key = #{uniqueKey}, status = #{status}, job_key = #{jobKey}, job_status = #{jobStatus}, city = #{city}, experience = #{experience}, education = #{education}, min_salary = #{minSalary}, max_salary = #{maxSalary}, salary_unit = #{salaryUnit}, skills = #{skills}, job_desc = #{jobDesc}, publish_time = #{publishTime}, last_seen_at = #{lastSeenAt},
WHERE id = #{id}

mapper.select:
SELECT j.*
FROM job j


        AND (j.title LIKE CONCAT('%', #{keyword}, '%')
          OR j.company_name LIKE CONCAT('%', #{keyword}, '%')
          OR j.skills LIKE CONCAT('%', #{keyword}, '%')
          OR j.job_desc LIKE CONCAT('%', #{keyword}, '%'))


        AND j.city = #{city}


        AND j.company_name LIKE CONCAT('%', #{companyName}, '%')


        AND j.experience = #{experience}


        AND j.education = #{education}


        AND j.job_status = #{status}


ORDER BY j.publish_time DESC

SELECT AVG((min_salary + max_salary) / 2) AS avgSalary
FROM job

    status = 1

        AND city = #{city}


        AND experience = #{experience}


        AND education = #{education}


        AND skills LIKE CONCAT('%', #{skills}, '%')
